// Reserva atómica de la clave ANTES de tocar el gateway.
// El índice único sobre "key" convierte la carrera en un error controlado.
func (s *Store) Reserve(ctx context.Context, key string, req Hash) (*Op, error) {
    op := Op{Key: key, ReqHash: req, Status: StatusPending, CreatedAt: now()}
    _, err := s.ops.InsertOne(ctx, op)
    if mongo.IsDuplicateKeyError(err) {
        existing, _ := s.findByKey(ctx, key)
        if existing.ReqHash != req {
            return nil, ErrKeyReused // misma clave, cuerpo distinto: rechazar
        }
        return existing, ErrAlreadyProcessed // devolver respuesta archivada
    }
    return &op, err
}

func (s *Service) Charge(ctx context.Context, req Request) (Result, error) {
    ch := make(chan Result) // sin búfer: el envío bloquea

    go func() {
        res := s.provider.Process(req) // puede tardar segundos
        ch <- res                      // ← si nadie lee, esto bloquea PARA SIEMPRE
    }()

    select {
    case res := <-ch:
        return res, nil
    case <-ctx.Done(): // timeout: el caller se va…
        return Result{}, ctx.Err() // …y la goroutine queda huérfana
    }
}

func (s *Service) Charge(ctx context.Context, req Request) (Result, error) {
    ch := make(chan Result, 1) // búfer 1: el envío SIEMPRE completa

    go func() {
        ch <- s.provider.Process(ctx, req) // el contexto viaja hacia dentro
    }()

    select {
    case res := <-ch:
        return res, nil
    case <-ctx.Done():
        return Result{}, ctx.Err() // la goroutine escribirá al búfer y morirá
    }
}
